      toast({ title: "Please fill in all required fields", variant: "destructive" });
      return;
    }
    setSubmitting(true);
    try {
      await persistRequest(target, mode, form);
      toast({
        title: isEnquiry ? "Enquiry sent!" : "Intro request sent!",
